import React, { useEffect, useState } from "react";
import axios from "axios";
import "bootstrap/dist/css/bootstrap.min.css";

export default function VentasPage() {
  const [ventas, setVentas] = useState([]);
  const [busqueda, setBusqueda] = useState("");
  const [cargando, setCargando] = useState(false);

  const [mostrarModal, setMostrarModal] = useState(false);
  const [editando, setEditando] = useState(null);
  const [guardando, setGuardando] = useState(false);

  const [ventaData, setVentaData] = useState({
    clienteID: "",
    total: "",
    fecha: "",
    metodoPago: "",
  });

  // Paginación
  const [paginaActual, setPaginaActual] = useState(1);
  const ventasPorPagina = 5;

  useEffect(() => {
    obtenerVentas();
  }, []);

  const obtenerVentas = async () => {
    setCargando(true);
    try {
      const res = await axios.get("http://localhost:5000/api/ventas");
      setVentas(res.data);
    } catch (error) {
      console.error("❌ Error al obtener ventas:", error);
    } finally {
      setCargando(false);
    }
  };

  const handleAbrirModal = (venta = null) => {
    if (venta) {
      setEditando(venta.id);
      setVentaData({
        clienteID: venta.clienteID,
        total: venta.total,
        fecha: venta.fecha.split("T")[0],
        metodoPago: venta.metodoPago,
      });
    } else {
      setEditando(null);
      setVentaData({
        clienteID: "",
        total: "",
        fecha: new Date().toISOString().split("T")[0],
        metodoPago: "",
      });
    }
    setMostrarModal(true);
  };

  const handleCerrarModal = () => setMostrarModal(false);

  const handleGuardarVenta = async (e) => {
    e.preventDefault();
    setGuardando(true);
    try {
      if (editando) {
        await axios.put(
          `http://localhost:5000/api/ventas/${editando}`,
          ventaData
        );
      } else {
        await axios.post("http://localhost:5000/api/ventas", ventaData);
      }
      await obtenerVentas();
      setMostrarModal(false);
    } catch (error) {
      console.error("❌ Error al guardar venta:", error);
      alert("Error al guardar venta");
    } finally {
      setGuardando(false);
    }
  };

  const eliminarVenta = async (id) => {
    if (!window.confirm("¿Seguro que deseas eliminar esta venta?")) return;
    try {
      await axios.delete(`http://localhost:5000/api/ventas/${id}`);
      await obtenerVentas();
    } catch (error) {
      console.error("❌ Error al eliminar venta:", error);
      alert("Error al eliminar venta");
    }
  };

  // Filtro de búsqueda
  const ventasFiltradas = ventas.filter(
    (v) =>
      v.cliente?.nombre?.toLowerCase().includes(busqueda.toLowerCase()) ||
      v.id.toString().includes(busqueda)
  );

  // Paginación lógica
  const indiceInicio = (paginaActual - 1) * ventasPorPagina;
  const ventasPaginadas = ventasFiltradas.slice(
    indiceInicio,
    indiceInicio + ventasPorPagina
  );
  const totalPaginas = Math.ceil(ventasFiltradas.length / ventasPorPagina);

  return (
    <div className="container mt-5">
      {/* Header con buscador y botón */}
      <div className="d-flex justify-content-between align-items-center mb-4">
        <div className="d-flex align-items-center" style={{ gap: "10px" }}>
          <input
            type="text"
            className="form-control"
            placeholder="Buscar por cliente o ID..."
            style={{ width: "250px" }}
            value={busqueda}
            onChange={(e) => setBusqueda(e.target.value)}
          />
        </div>
        <button className="btn btn-primary" onClick={() => handleAbrirModal()}>
          ➕ Registrar Venta
        </button>
      </div>

      {/* Tabla */}
      {cargando ? (
        <p className="text-center text-muted">Cargando ventas...</p>
      ) : ventasPaginadas.length > 0 ? (
        <div className="table-responsive">
          <table className="table table-bordered align-middle text-center">
            <thead className="table-dark">
              <tr>
                <th>ID</th>
                <th>Cliente</th>
                <th>Fecha</th>
                <th>Método de Pago</th>
                <th>Total ($)</th>
                <th>Acciones</th>
              </tr>
            </thead>
            <tbody>
              {ventasPaginadas.map((v) => (
                <tr key={v.id}>
                  <td>{v.id}</td>
                  <td>{v.cliente?.nombre || "—"}</td>
                  <td>{new Date(v.fecha).toLocaleDateString()}</td>
                  <td>{v.metodoPago}</td>
                  <td>{v.total}</td>
                  <td>
                    <button
                      className="btn btn-warning btn-sm me-2"
                      onClick={() => handleAbrirModal(v)}
                    >
                      ✏️ Editar
                    </button>
                    <button
                      className="btn btn-danger btn-sm"
                      onClick={() => eliminarVenta(v.id)}
                    >
                      🗑 Eliminar
                    </button>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>

          {/* Paginador */}
          <nav className="d-flex justify-content-center mt-3">
            <ul className="pagination">
              <li className={`page-item ${paginaActual === 1 ? "disabled" : ""}`}>
                <button
                  className="page-link"
                  onClick={() => setPaginaActual(paginaActual - 1)}
                >
                  Anterior
                </button>
              </li>
              {Array.from({ length: totalPaginas }, (_, i) => (
                <li
                  key={i}
                  className={`page-item ${
                    paginaActual === i + 1 ? "active" : ""
                  }`}
                >
                  <button
                    className="page-link"
                    onClick={() => setPaginaActual(i + 1)}
                  >
                    {i + 1}
                  </button>
                </li>
              ))}
              <li
                className={`page-item ${
                  paginaActual === totalPaginas ? "disabled" : ""
                }`}
              >
                <button
                  className="page-link"
                  onClick={() => setPaginaActual(paginaActual + 1)}
                >
                  Siguiente
                </button>
              </li>
            </ul>
          </nav>
        </div>
      ) : (
        <p className="text-center text-muted">No hay ventas registradas.</p>
      )}

      {/* Modal */}
      {mostrarModal && (
        <div
          className="modal fade show d-block"
          tabIndex="-1"
          style={{ background: "rgba(0,0,0,0.5)" }}
        >
          <div className="modal-dialog">
            <div className="modal-content shadow">
              <div className="modal-header">
                <h5 className="modal-title">
                  {editando ? "Editar Venta" : "Registrar Venta"}
                </h5>
                <button
                  type="button"
                  className="btn-close"
                  onClick={handleCerrarModal}
                ></button>
              </div>
              <form onSubmit={handleGuardarVenta}>
                <div className="modal-body">
                  <div className="mb-3">
                    <label className="form-label">ID Cliente</label>
                    <input
                      type="number"
                      className="form-control"
                      value={ventaData.clienteID}
                      onChange={(e) =>
                        setVentaData({
                          ...ventaData,
                          clienteID: e.target.value,
                        })
                      }
                      required
                    />
                  </div>
                  <div className="mb-3">
                    <label className="form-label">Fecha</label>
                    <input
                      type="date"
                      className="form-control"
                      value={ventaData.fecha}
                      onChange={(e) =>
                        setVentaData({
                          ...ventaData,
                          fecha: e.target.value,
                        })
                      }
                      required
                    />
                  </div>
                  <div className="mb-3">
                    <label className="form-label">Método de Pago</label>
                    <select
                      className="form-select"
                      value={ventaData.metodoPago}
                      onChange={(e) =>
                        setVentaData({
                          ...ventaData,
                          metodoPago: e.target.value,
                        })
                      }
                      required
                    >
                      <option value="">Seleccionar...</option>
                      <option value="efectivo">Efectivo</option>
                      <option value="tarjeta">Tarjeta</option>
                      <option value="transferencia">Transferencia</option>
                    </select>
                  </div>
                  <div className="mb-3">
                    <label className="form-label">Total ($)</label>
                    <input
                      type="number"
                      className="form-control"
                      value={ventaData.total}
                      onChange={(e) =>
                        setVentaData({
                          ...ventaData,
                          total: e.target.value,
                        })
                      }
                      required
                    />
                  </div>
                </div>
                <div className="modal-footer">
                  <button
                    type="button"
                    className="btn btn-secondary"
                    onClick={handleCerrarModal}
                  >
                    Cancelar
                  </button>
                  <button
                    type="submit"
                    className="btn btn-primary"
                    disabled={guardando}
                  >
                    {guardando
                      ? "Guardando..."
                      : editando
                      ? "Actualizar"
                      : "Guardar"}
                  </button>
                </div>
              </form>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}
